import $ from 'jquery';
import {Edge} from 'butterfly-dag';

class BaseEdge extends Edge {
  draw(obj) {
    let path = super.draw(obj);
    if (this.options.color) {
      $(path).addClass(this.options.color);
    }
    return path;
  }

  drawArrow(isShow) {
    let dom = super.drawArrow(isShow);
    if (this.options.color) {
      $(dom).addClass(this.options.color);
    }
    return dom;
  }

  drawLabel(text) {
    let dom = null;
    if (text) {
      dom = $(`<span class="label">${text}</span>`)[0];
    }
    return dom;
  }
}

export default BaseEdge;

import {Canvas} from 'butterfly-dag';
import ReactDOM from 'react-dom';
import React, {Component} from 'react';

import mockData from './data.js';

import './index.less';
import 'butterfly-dag/dist/index.css';

class Emergency2 extends Component {
  componentDidMount() {
    let root = document.getElementById('dag-canvas');
    this.canvas = new Canvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          type: 'Manhattan',
          arrow: true
        },
        // 拖动边缘处自动适应画布
        autoFixCanvas: {
          enable: true
        }
      }
    });
    this.canvas.draw(mockData);
  }

  render() {
    return (
      <div className='emergency2-page'>
        <div className="emergency2-canvas" id="dag-canvas">
        </div>
      </div>
    );
  }
}

ReactDOM.render(<Emergency2 />, document.getElementById('root'));

